const brandSlugRemap: Record<string, string> = {"bw-technologies":"bw-techno","hadeed-safety-wear":"hadeed","weicon":"welcon","haswel-electrode":"haswel-elect"};

const brandLogoMap: Record<string, string> = {
  "total-tools": "/brands/total%20tools%20logo.jpg",
  "3m": "/brands/3m%20logo.png",
  "ambersil": "/brands/ambersil%20logo.png",
  "hadeed-safety-wear": "/brands/HADEENLOGO.png",
  "norton": "/brands/Norton-logo.png",
  "makita": "/brands/makita-logo.webp",
  "deltaplus": "/brands/deltaplus.jpg",
  "bw-technologies": "/brands/b%20w%20logo.png",
  "jsp": "/brands/JSP%20LOGL.png",
  "weicon": "/brands/WELCON%20LOGO.jpeg",
  "uni-t": "/brands/UNI-T%20LOGO.png",
  "victor": "/brands/Victor%20LOGO.webp",
  "fluke": "/brands/FLUKE%20LOGO.png",
  "honeywell": "/brands/HUNEYWELLLOGO.png",
  "haswel-electrode": "/brands/KISWEL%20LOGO.png",
  "dewalt": "/brands/DEWALT%20LOGO.png",
  "stanley": "/brands/STANLEY.png",
  "rothenberger": "/brands/ROTHENBERGER%20LOGO.png",
  "crc": "/brands/CRC%20LOGO.png",
  "esab": "/brands/ESAB%20LOGO.png"
};

export function getBrandLogo(brandSlug: string): string {
  return brandLogoMap[brandSlug] || "/brands/HADEENLOGO.png";
}

export function getProductImages(brandSlug: string, categorySlug: string, subcategorySlug: string): string[] {
  const mappedBrand = brandSlugRemap[brandSlug] || brandSlug;
  const key = mappedBrand + "|" + categorySlug + "|" + subcategorySlug;
  const images = catalogMap[key];
  if (images && images.length > 0) return images;
  const prefix = mappedBrand + "|" + categorySlug + "|";
  const fallback = Object.keys(catalogMap).find(k => k.startsWith(prefix));
  if (fallback) return catalogMap[fallback];
  const brandPrefix = mappedBrand + "|";
  const brandFallback = Object.keys(catalogMap).find(k => k.startsWith(brandPrefix));
  if (brandFallback) return catalogMap[brandFallback];
  return ["/brands/HADEENLOGO.png"];
}

export function getProductImage(brandSlug: string, categorySlug: string, subcategorySlug: string): string {
  return getProductImages(brandSlug, categorySlug, subcategorySlug)[0];
}
